async def execute(self, inputs):
    v_type = inputs.get('type', 'string')
    val = inputs.get('value')

    try:
        if v_type == 'int': out = int(val) if val is not None else 0
        elif v_type == 'float': out = float(val) if val is not None else 0.0
        elif v_type == 'bool':
            if isinstance(val, str): out = val.lower() in ['true', '1', 'yes']
            else: out = bool(val)
        else: out = str(val) if val is not None else ""

        return {'out': out}
    except Exception as e:
        self.log_error(f"Variable cast error: {e}")
        return {'out': val}
